1	//! Error text renderers.
2	//!
3	//! Two tiers, both observed to exit 1:
4	//! - cmdargs-level parse errors, produced by [`crate::parse`] ([`CliError`]).
5	//! - runtime errors printed after the maude preamble (file-open failures and
6	//!   application `error` call sites); these are text producers the caller emits
7	//!   during processing, not parse-time results.
8	//!
9	//! Every literal string here is compatibility output copied from observed oracle
10	//! output (see `workspace/captures/`).
11	
12	use crate::help::render_help;
13	use crate::modes::Mode;
14	
15	/// A ready-to-print error with its exit code (observed: always 1).
16	#[derive(Debug, Clone, PartialEq, Eq)]
17	pub struct CliError {
18	    pub text: String,
19	    pub exit_code: i32,
20	}
21	
22	impl CliError {
23	    fn code1(text: String) -> Self {
24	        CliError { text, exit_code: 1 }
25	    }
26	}
27	
28	// ---- cmdargs-level parse errors ----------------------------------------------
29	
30	/// `Unknown flag: <flag>` (bare one-liner; `flag` includes its dashes).
31	pub fn unknown_flag(flag: &str) -> CliError {
32	    CliError::code1(format!("Unknown flag: {}\n", flag))
33	}
34	
35	/// `Unhandled argument to flag, none expected: <token>` for a value given to a
36	/// valueless flag (`token` is the whole `--flag=value`).
37	pub fn unhandled_argument(token: &str) -> CliError {
38	    CliError::code1(format!("Unhandled argument to flag, none expected: {}\n", token))
39	}
40	
41	/// `Ambiguous mode '<token>', could be any of: <names…>`.
42	pub fn ambiguous_mode(token: &str, names: &[&str]) -> CliError {
43	    CliError::code1(format!(
44	        "Ambiguous mode '{}', could be any of: {}\n",
45	        token,
46	        names.join(" ")
47	    ))
48	}
49	
50	/// `error: no input files given` followed by a blank line and the mode's full
51	/// help page.
52	pub fn no_input_files(mode: Mode) -> CliError {
53	    CliError::code1(format!("error: no input files given\n\n{}", render_help(mode)))
54	}
55	
56	/// `error: directory '<dir>' does not exist.` followed by a blank line and the
57	/// mode's full help page. (Interactive WORKDIR check; requires the filesystem,
58	/// so it is a caller-invoked renderer rather than a parse-time result.)
59	pub fn directory_does_not_exist(dir: &str, mode: Mode) -> CliError {
60	    CliError::code1(format!(
61	        "error: directory '{}' does not exist.\n\n{}",
62	        dir,
63	        render_help(mode)
64	    ))
65	}
66	
67	// ---- runtime errors (printed after the maude preamble) -----------------------
68	
69	/// Reason an input file could not be opened, with its exact message suffix.
70	#[derive(Debug, Clone, Copy)]
71	pub enum OpenFileError {
72	    DoesNotExist,
73	    PermissionDenied,
74	    IsDirectory,
75	}
76	
77	impl OpenFileError {
78	    fn suffix(self) -> &'static str {
79	        match self {
80	            OpenFileError::DoesNotExist => "openFile: does not exist (No such file or directory)",
81	            OpenFileError::PermissionDenied => "openFile: permission denied (Permission denied)",
82	            OpenFileError::IsDirectory => "openFile: inappropriate type (is a directory)",
83	        }
84	    }
85	}
86	
87	/// `tamarin-prover: <path>: <reason>` — a file-open failure line.
88	pub fn open_file_error(path: &str, reason: OpenFileError) -> String {
89	    format!("tamarin-prover: {}: {}\n", path, reason.suffix())
90	}
91	
92	/// An application `error` call with the observed Haskell CallStack. `message` is
93	/// one of the known messages, e.g. `bound: invalid bound given` or
94	/// `output mode not supported.`.
95	pub fn app_error(message: &str) -> String {
96	    format!(
97	        "tamarin-prover: {}\nCallStack (from HasCallStack):\n  error, called at src/Main/Mode/Batch.hs:162:33 in main:Main.Mode.Batch\n",
98	        message
99	    )
100	}
101

1	//! Thin driver exercising the CLI text surface.
2	//!
3	//! Handles the pure-text paths (help, version, parse errors) byte-for-byte so
4	//! they can be verified against the black-box binary. `Run` has no prover engine
5	//! behind it here — real integration wires the parsed [`cli_clean::RunSpec`] into
6	//! the prover and uses [`cli_clean::framing`] to wrap its output.
7	
8	use std::process::exit;
9	
10	use cli_clean::version::{MaudeInfo, VersionInfo};
11	use cli_clean::{parse, render_version, Command};
12	
13	/// Version slots as observed from the reference build. Real integration injects
14	/// the actual build metadata of the hosting binary.
15	fn observed_version_info() -> VersionInfo {
16	    VersionInfo {
17	        maude: MaudeInfo::default(),
18	        tamarin_version: "1.13.0".to_string(),
19	        copyright_years: "2010-2023".to_string(),
20	        git_description: "0234f6a1abee25677c0accef62de0ac2883b0347 (with uncommited changes), branch: HEAD"
21	            .to_string(),
22	        compiled_at: "2026-07-16 18:33:16.036427196 UTC".to_string(),
23	    }
24	}
25	
26	fn main() {
27	    let argv: Vec<String> = std::env::args().skip(1).collect();
28	    match parse(&argv) {
29	        Ok(Command::Help(mode)) => {
30	            print!("{}", cli_clean::render_help(mode));
31	            exit(0);
32	        }
33	        Ok(Command::Version) => {
34	            print!("{}", render_version(&observed_version_info()));
35	            exit(0);
36	        }
37	        Ok(Command::Run(spec)) => {
38	            // Text-surface stub: no prover engine in this crate.
39	            eprintln!(
40	                "[cli-clean] parsed: mode={:?} positional={:?} flags={:?}",
41	                spec.mode, spec.positional, spec.options.flags
42	            );
43	            exit(0);
44	        }
45	        Err(e) => {
46	            eprint!("{}", e.text);
47	            exit(e.exit_code);
48	        }
49	    }
50	}
51

1	//! Unit E — `.spthy` macro expansion (clean-room).
2	//!
3	//! `expand(theory)` returns an equivalent macro-free theory: every macro call
4	//! at every use site is replaced by its transitively-substituted body, and the
5	//! `macros:` declarations are dropped. See ../BEHAVIOR.md for the observed
6	//! semantics this implements; every rule below traces to a `[Qn]` observation.
7	//!
8	//! Summary of the semantics implemented here:
9	//!  * a macro `name(f1..fk) = body`; call `name(a1..ak)` binds `fi := ai` and
10	//!    substitutes **simultaneously** (parallel / capture-avoiding)          [Q7]
11	//!  * a formal matches a body variable by **full identity incl. sort**; `~x`
12	//!    and `$x` do NOT match an untagged formal `x` and stay free            [Q27,Q28]
13	//!  * bodies may call only strictly-earlier macros ⇒ the macro dependency
14	//!    graph is a DAG, so expansion always terminates                        [Q8,Q19,Q20]
15	//!  * expansion is transitive: a body's own macro calls are expanded too    [Q9,Q18]
16	//!  * at the AST level a call's arg-count already equals the macro arity
17	//!    (the parser packs/【rejects mismatches); `expand` no-ops on a mismatch) [Q11,Q12,Q15,Q16,Q17]
18	
19	pub mod ast;
20	
21	use std::collections::HashMap;
22	use ast::*;
23	
24	/// Table of macros whose bodies are already fully expanded (macro-free),
25	/// keyed by macro name. Formals are matched against body variables by full
26	/// `VarSpec` identity, so the substitution map is keyed by `VarSpec`.
27	#[derive(Default)]
28	struct MacroTable {
29	    by_name: HashMap<String, (Vec<VarSpec>, Term)>,
30	}
31	
32	impl MacroTable {
33	    fn get(&self, name: &str) -> Option<&(Vec<VarSpec>, Term)> {
34	        self.by_name.get(name)
35	    }
36	}
37	
38	/// Expand every macro use in `theory` and drop the macro declarations.
39	///
40	/// The result, fed back to the oracle, reproduces the reasoning content the
41	/// oracle computes for the original (modulo-AC variants / expanded-formula /
42	/// guarded-formula), which is byte-identical to a hand-inlined equivalent
43	/// (verified by workspace/byteparity.sh).
44	pub fn expand(theory: &Theory) -> Theory {
45	    let table = build_table(theory);
46	    let items = theory
47	        .items
48	        .iter()
49	        .filter(|it| !matches!(it, TheoryItem::Macros(_)))
50	        .map(|it| expand_item(it, &table))
51	        .collect();
52	    Theory {
53	        is_diff: theory.is_diff,
54	        name: theory.name.clone(),
55	        configuration: theory.configuration.clone(),
56	        items,
57	    }
58	}
59	
60	/// Build the macro table with fully-expanded (macro-free) bodies.
61	///
62	/// Macros are processed in declaration order; each body is expanded against the
63	/// macros defined strictly before it. Forward/self/mutual references are parse
64	/// errors upstream [Q8,Q19,Q20], so "earlier only" is complete and cannot loop.
65	fn build_table(theory: &Theory) -> MacroTable {
66	    let mut table = MacroTable::default();
67	    for item in &theory.items {
68	        if let TheoryItem::Macros(ms) = item {
69	            for m in ms {
70	                let body = expand_term(&m.body, &table);
71	                table.by_name.insert(m.name.clone(), (m.args.clone(), body));
72	            }
73	        }
74	    }
75	    table
76	}
77	
78	// ---- term-level expansion -------------------------------------------------
79	
80	/// Bottom-up macro expansion of a term. Arguments are expanded first, then a
81	/// macro call is replaced by its body with formals bound to the expanded args.
82	fn expand_term(t: &Term, table: &MacroTable) -> Term {
83	    match t {
84	        Term::Var(_)
85	        | Term::PubLit(_)
86	        | Term::FreshLit(_)
87	        | Term::NatLit(_)
88	        | Term::Number(_)
89	        | Term::NumberOne
90	        | Term::NatOne
91	        | Term::DhNeutral => t.clone(),
92	
93	        Term::App(name, args) => {
94	            let args: Vec<Term> = args.iter().map(|a| expand_term(a, table)).collect();
95	            if let Some((formals, body)) = table.get(name) {
96	                // At the AST level arg-count == arity for a valid parse. If it
97	                // ever differs (defensive), leave the call unexpanded.
98	                if formals.len() == args.len() {
99	                    let subst = build_subst(formals, &args);
100	                    // `body` is already macro-free; a simultaneous substitution
101	                    // of macro-free args therefore yields a macro-free term.
102	                    return substitute_term(body, &subst);
103	                }
104	            }
105	            Term::App(name.clone(), args)
106	        }
107	
108	        Term::AlgApp(name, a, b) => Term::AlgApp(
109	            name.clone(),
110	            Box::new(expand_term(a, table)),
111	            Box::new(expand_term(b, table)),
112	        ),
113	        Term::Pair(ts) => Term::Pair(ts.iter().map(|x| expand_term(x, table)).collect()),
114	        Term::Diff(a, b) => Term::Diff(
115	            Box::new(expand_term(a, table)),
116	            Box::new(expand_term(b, table)),
117	        ),
118	        Term::BinOp(op, a, b) => Term::BinOp(
119	            *op,
120	            Box::new(expand_term(a, table)),
121	            Box::new(expand_term(b, table)),
122	        ),
123	        Term::PatMatch(a) => Term::PatMatch(Box::new(expand_term(a, table))),
124	    }
125	}
126	
127	/// Build the simultaneous substitution `formal_i := arg_i`, keyed by the full
128	/// `VarSpec` of each formal (so sort/idx participate in matching) [Q27,Q28].
129	fn build_subst(formals: &[VarSpec], args: &[Term]) -> HashMap<VarSpec, Term> {
130	    formals
131	        .iter()
132	        .cloned()
133	        .zip(args.iter().cloned())
134	        .collect()
135	}
136	
137	/// Apply a simultaneous substitution to `t`. A `Var` that matches a key is
138	/// replaced by the bound term **without** re-descending into it (parallel
139	/// substitution — no capture) [Q7]. Non-matching variables (incl. differently
140	/// sorted `~x`/`$x`) are left untouched [Q27,Q28].
141	fn substitute_term(t: &Term, subst: &HashMap<VarSpec, Term>) -> Term {
142	    match t {
143	        Term::Var(v) => match subst.get(v) {
144	            Some(bound) => bound.clone(),
145	            None => t.clone(),
146	        },
147	        Term::PubLit(_)
148	        | Term::FreshLit(_)
149	        | Term::NatLit(_)
150	        | Term::Number(_)
151	        | Term::NumberOne
152	        | Term::NatOne
153	        | Term::DhNeutral => t.clone(),
154	        Term::App(name, args) => Term::App(
155	            name.clone(),
156	            args.iter().map(|a| substitute_term(a, subst)).collect(),
157	        ),
158	        Term::AlgApp(name, a, b) => Term::AlgApp(
159	            name.clone(),
160	            Box::new(substitute_term(a, subst)),
161	            Box::new(substitute_term(b, subst)),
162	        ),
163	        Term::Pair(ts) => Term::Pair(ts.iter().map(|x| substitute_term(x, subst)).collect()),
164	        Term::Diff(a, b) => Term::Diff(
165	            Box::new(substitute_term(a, subst)),
166	            Box::new(substitute_term(b, subst)),
167	        ),
168	        Term::BinOp(op, a, b) => Term::BinOp(
169	            *op,
170	            Box::new(substitute_term(a, subst)),
171	            Box::new(substitute_term(b, subst)),
172	        ),
173	        Term::PatMatch(a) => Term::PatMatch(Box::new(substitute_term(a, subst))),
174	    }
175	}
176	
177	// ---- structural recursion through the theory ------------------------------
178	
179	fn expand_fact(f: &Fact, table: &MacroTable) -> Fact {
180	    Fact {
181	        persistent: f.persistent,
182	        name: f.name.clone(),
183	        args: f.args.iter().map(|a| expand_term(a, table)).collect(),
184	        annotations: f.annotations.clone(),
185	    }
186	}
187	
188	fn expand_atom(a: &Atom, table: &MacroTable) -> Atom {
189	    match a {
190	        Atom::Eq(x, y) => Atom::Eq(expand_term(x, table), expand_term(y, table)),
191	        Atom::Less(x, y) => Atom::Less(expand_term(x, table), expand_term(y, table)),
192	        Atom::LessMset(x, y) => Atom::LessMset(expand_term(x, table), expand_term(y, table)),
193	        Atom::Subterm(x, y) => Atom::Subterm(expand_term(x, table), expand_term(y, table)),
194	        Atom::Action(f, t) => Atom::Action(expand_fact(f, table), expand_term(t, table)),
195	        Atom::Last(t) => Atom::Last(expand_term(t, table)),
196	        Atom::Pred(f) => Atom::Pred(expand_fact(f, table)),
197	    }
198	}
199	
200	fn expand_formula(phi: &Formula, table: &MacroTable) -> Formula {
201	    match phi {
202	        Formula::False => Formula::False,
203	        Formula::True => Formula::True,
204	        Formula::Atom(a) => Formula::Atom(expand_atom(a, table)),
205	        Formula::Not(p) => Formula::Not(Box::new(expand_formula(p, table))),
206	        Formula::And(p, q) => Formula::And(
207	            Box::new(expand_formula(p, table)),
208	            Box::new(expand_formula(q, table)),
209	        ),
210	        Formula::Or(p, q) => Formula::Or(
211	            Box::new(expand_formula(p, table)),
212	            Box::new(expand_formula(q, table)),
213	        ),
214	        Formula::Implies(p, q) => Formula::Implies(
215	            Box::new(expand_formula(p, table)),
216	            Box::new(expand_formula(q, table)),
217	        ),
218	        Formula::Iff(p, q) => Formula::Iff(
219	            Box::new(expand_formula(p, table)),
220	            Box::new(expand_formula(q, table)),
221	        ),
222	        Formula::Forall(vs, p) => {
223	            Formula::Forall(vs.clone(), Box::new(expand_formula(p, table)))
224	        }
225	        Formula::Exists(vs, p) => {
226	            Formula::Exists(vs.clone(), Box::new(expand_formula(p, table)))
227	        }
228	    }
229	}
230	
231	fn expand_let(b: &LetBinding, table: &MacroTable) -> LetBinding {
232	    // A macro call may appear in the let value [Q23]; the bound pattern `var`
233	    // is a variable/pattern and is expanded too for uniformity.
234	    LetBinding {
235	        var: expand_term(&b.var, table),
236	        value: expand_term(&b.value, table),
237	    }
238	}
239	
240	fn expand_rule(r: &Rule, table: &MacroTable) -> Rule {
241	    Rule {
242	        name: r.name.clone(),
243	        modulo: r.modulo.clone(),
244	        attributes: r.attributes.clone(),
245	        let_block: r.let_block.iter().map(|b| expand_let(b, table)).collect(),
246	        premises: r.premises.iter().map(|f| expand_fact(f, table)).collect(),
247	        actions: r.actions.iter().map(|f| expand_fact(f, table)).collect(),
248	        conclusions: r.conclusions.iter().map(|f| expand_fact(f, table)).collect(),
249	        embedded_restrictions: r
250	            .embedded_restrictions
251	            .iter()
252	            .map(|p| expand_formula(p, table))
253	            .collect(),
254	        variants: r.variants.iter().map(|v| expand_rule(v, table)).collect(),
255	        left_right: r.left_right.as_ref().map(|(l, rr)| {
256	            (
257	                Box::new(expand_rule(l, table)),
258	                Box::new(expand_rule(rr, table)),
259	            )
260	        }),
261	    }
262	}
263	
264	fn expand_sapic_action(a: &SapicAction, table: &MacroTable) -> SapicAction {
265	    match a {
266	        SapicAction::New(v) => SapicAction::New(v.clone()),
267	        SapicAction::Insert(k, v) => {
268	            SapicAction::Insert(expand_term(k, table), expand_term(v, table))
269	        }
270	        SapicAction::Delete(k) => SapicAction::Delete(expand_term(k, table)),
271	        SapicAction::ChIn { chan, msg } => SapicAction::ChIn {
272	            chan: chan.as_ref().map(|c| expand_term(c, table)),
273	            msg: expand_term(msg, table),
274	        },
275	        SapicAction::ChOut { chan, msg } => SapicAction::ChOut {
276	            chan: chan.as_ref().map(|c| expand_term(c, table)),
277	            msg: expand_term(msg, table),
278	        },
279	        SapicAction::Lock(t) => SapicAction::Lock(expand_term(t, table)),
280	        SapicAction::Unlock(t) => SapicAction::Unlock(expand_term(t, table)),
281	        SapicAction::Event(f) => SapicAction::Event(expand_fact(f, table)),
282	        SapicAction::Msr { prems, acts, concs, restrictions } => SapicAction::Msr {
283	            prems: prems.iter().map(|f| expand_fact(f, table)).collect(),
284	            acts: acts.iter().map(|f| expand_fact(f, table)).collect(),
285	            concs: concs.iter().map(|f| expand_fact(f, table)).collect(),
286	            restrictions: restrictions.iter().map(|p| expand_formula(p, table)).collect(),
287	        },
288	    }
289	}
290	
291	fn expand_condition(c: &Condition, table: &MacroTable) -> Condition {
292	    match c {
293	        Condition::Eq(x, y) => Condition::Eq(expand_term(x, table), expand_term(y, table)),
294	        Condition::Formula(p) => Condition::Formula(expand_formula(p, table)),
295	    }
296	}
297	
298	fn expand_comb(c: &ProcessComb, table: &MacroTable) -> ProcessComb {
299	    match c {
300	        ProcessComb::Parallel => ProcessComb::Parallel,
301	        ProcessComb::Ndc => ProcessComb::Ndc,
302	        ProcessComb::Cond(cond) => ProcessComb::Cond(expand_condition(cond, table)),
303	        ProcessComb::Lookup(t, v) => ProcessComb::Lookup(expand_term(t, table), v.clone()),
304	        ProcessComb::Let { pat, value } => ProcessComb::Let {
305	            pat: expand_term(pat, table),
306	            value: expand_term(value, table),
307	        },
308	    }
309	}
310	
311	fn expand_process(p: &Process, table: &MacroTable) -> Process {
312	    match p {
313	        Process::Null => Process::Null,
314	        Process::Action { action, body } => Process::Action {
315	            action: expand_sapic_action(action, table),
316	            body: Box::new(expand_process(body, table)),
317	        },
318	        Process::Comb { comb, left, right } => Process::Comb {
319	            comb: expand_comb(comb, table),
320	            left: Box::new(expand_process(left, table)),
321	            right: Box::new(expand_process(right, table)),
322	        },
323	        Process::Replication(b) => Process::Replication(Box::new(expand_process(b, table))),
324	        Process::Call { name, args } => Process::Call {
325	            name: name.clone(),
326	            args: args.iter().map(|a| expand_term(a, table)).collect(),
327	        },
328	        Process::AtAnnotation(b, t) => {
329	            Process::AtAnnotation(Box::new(expand_process(b, table)), expand_term(t, table))
330	        }
331	    }
332	}
333	
334	fn expand_restriction(r: &Restriction, table: &MacroTable) -> Restriction {
335	    Restriction {
336	        name: r.name.clone(),
337	        formula: expand_formula(&r.formula, table),
338	        attributes: r.attributes.clone(),
339	    }
340	}
341	
342	fn expand_lemma(l: &Lemma, table: &MacroTable) -> Lemma {
343	    Lemma {
344	        name: l.name.clone(),
345	        modulo: l.modulo.clone(),
346	        attributes: l.attributes.clone(),
347	        trace_quantifier: l.trace_quantifier.clone(),
348	        formula: expand_formula(&l.formula, table),
349	        proof: l.proof.clone(),
350	        plaintext: l.plaintext.clone(),
351	    }
352	}
353	
354	fn expand_predicate(p: &Predicate, table: &MacroTable) -> Predicate {
355	    Predicate {
356	        fact: expand_fact(&p.fact, table),
357	        formula: expand_formula(&p.formula, table),
358	    }
359	}
360	
361	fn expand_item(it: &TheoryItem, table: &MacroTable) -> TheoryItem {
362	    match it {
363	        TheoryItem::Rule(r) => TheoryItem::Rule(expand_rule(r, table)),
364	        TheoryItem::IntrRule(r) => TheoryItem::IntrRule(expand_rule(r, table)),
365	        TheoryItem::Restriction(r) => TheoryItem::Restriction(expand_restriction(r, table)),
366	        TheoryItem::LegacyAxiom(r) => TheoryItem::LegacyAxiom(expand_restriction(r, table)),
367	        TheoryItem::Lemma(l) => TheoryItem::Lemma(expand_lemma(l, table)),
368	        TheoryItem::AccLemma(a) => TheoryItem::AccLemma(AccLemma {
369	            name: a.name.clone(),
370	            attributes: a.attributes.clone(),
371	            formula: expand_formula(&a.formula, table),
372	            case_test_idents: a.case_test_idents.clone(),
373	        }),
374	        TheoryItem::CaseTest(c) => TheoryItem::CaseTest(CaseTest {
375	            name: c.name.clone(),
376	            formula: expand_formula(&c.formula, table),
377	        }),
378	        TheoryItem::Predicates(ps) => {
379	            TheoryItem::Predicates(ps.iter().map(|p| expand_predicate(p, table)).collect())
380	        }
381	        TheoryItem::ProcessDef(pd) => TheoryItem::ProcessDef(ProcessDef {
382	            name: pd.name.clone(),
383	            vars: pd.vars.clone(),
384	            body: expand_process(&pd.body, table),
385	        }),
386	        TheoryItem::TopLevelProcess(p) => {
387	            TheoryItem::TopLevelProcess(expand_process(p, table))
388	        }
389	        TheoryItem::EquivLemma(a, b) => {
390	            TheoryItem::EquivLemma(expand_process(a, table), expand_process(b, table))
391	        }
392	        TheoryItem::DiffEquivLemma(p) => {
393	            TheoryItem::DiffEquivLemma(expand_process(p, table))
394	        }
395	        // Equations carry terms; expand uniformly (a no-op when they contain no
396	        // macro call — not observed in the corpus, but handled for robustness).
397	        TheoryItem::Equations { convergent, eqs } => TheoryItem::Equations {
398	            convergent: *convergent,
399	            eqs: eqs
400	                .iter()
401	                .map(|e| Equation {
402	                    lhs: expand_term(&e.lhs, table),
403	                    rhs: expand_term(&e.rhs, table),
404	                })
405	                .collect(),
406	        },
407	        // Items with no macro-bearing terms are carried through unchanged. Macros
408	        // items are filtered out before this function is called.
409	        TheoryItem::Macros(_)
410	        | TheoryItem::Builtins(_)
411	        | TheoryItem::Functions(_)
412	        | TheoryItem::Options(_)
413	        | TheoryItem::Heuristic(_)
414	        | TheoryItem::Tactic(_)
415	        | TheoryItem::DiffLemma(_)
416	        | TheoryItem::Export { .. }
417	        | TheoryItem::FormalComment { .. }
418	        | TheoryItem::Define(_)
419	        | TheoryItem::Include(_) => it.clone(),
420	    }
421	}
