1	//! Clean-room detection of protocol facts with *injective instances*.
2	//!
3	//! Behaviour characterised entirely from black-box oracle observations of the
4	//! tamarin-prover web UI ("Fact Symbols with Injective Instances" on the
5	//! `/main/rules` page); see workspace/BEHAVIOR.md. No tamarin-prover source was
6	//! consulted.
7	//!
8	//! A linear fact tag `t` is injective iff:
9	//!   (I)  some rule contains `t` in *both* its premises and its conclusions
10	//!        (a state loop), and
11	//!   (II) in *every* rule, the multiset of `t`-conclusion first-arguments minus
12	//!        (by term equality) the multiset of `t`-premise first-arguments is a
13	//!        sub-multiset of the fresh names generated by that rule's `Fr` premises
14	//!        — i.e. every newly-created instance carries a distinct freshly
15	//!        generated name in its first argument.
16	
17	pub mod ast;
18	
19	use ast::{Fact, Rule, SortHint, Term, VarSpec};
20	use std::collections::BTreeSet;
21	
22	/// A fact tag: the fact symbol name together with its arity. Only linear
23	/// (non-persistent) tags can be injective.
24	pub type FactTag = (String, usize);
25	
26	/// Compute the set of protocol fact tags that have injective instances.
27	///
28	/// `rules` are the theory's multiset-rewriting rules (each rule's `premises`
29	/// and `conclusions` are inspected; `actions`, `variants`, `left_right` and
30	/// `embedded_restrictions` are irrelevant to the decision). For diff theories
31	/// the caller supplies the concrete left/right rule set.
32	pub fn injective_fact_instances(rules: &[Rule]) -> BTreeSet<FactTag> {
33	    // (I) Candidate tags: linear, arity >= 1, occurring in both premises and
34	    //     conclusions of one rule.
35	    let mut candidates: BTreeSet<FactTag> = BTreeSet::new();
36	    for r in rules {
37	        let prem_tags: BTreeSet<FactTag> = r
38	            .premises
39	            .iter()
40	            .filter(|f| is_linear_keyed(f))
41	            .map(tag_of)
42	            .collect();
43	        for f in &r.conclusions {
44	            if is_linear_keyed(f) {
45	                let t = tag_of(f);
46	                if prem_tags.contains(&t) {
47	                    candidates.insert(t);
48	                }
49	            }
50	        }
51	    }
52	
53	    // (II) Keep only candidates for which every rule creates new instances
54	    //      conservatively (net-new first-args are distinct freshly-generated
55	    //      names).
56	    candidates
57	        .into_iter()
58	        .filter(|t| rules.iter().all(|r| rule_conservative_for(r, t)))
59	        .collect()
60	}
61	
62	/// A fact can carry an injective key only if it is linear and has a first
63	/// argument.
64	fn is_linear_keyed(f: &Fact) -> bool {
65	    !f.persistent && !f.args.is_empty()
66	}
67	
68	fn tag_of(f: &Fact) -> FactTag {
69	    (f.name.clone(), f.args.len())
70	}
71	
72	fn has_tag(f: &Fact, t: &FactTag) -> bool {
73	    !f.persistent && f.name == t.0 && f.args.len() == t.1
74	}
75	
76	/// Check condition (II) for tag `t` on a single rule.
77	fn rule_conservative_for(r: &Rule, t: &FactTag) -> bool {
78	    // First-argument multisets for tag `t`.
79	    let prem_keys: Vec<&Term> = r
80	        .premises
81	        .iter()
82	        .filter(|f| has_tag(f, t))
83	        .map(|f| &f.args[0])
84	        .collect();
85	    let conc_keys: Vec<&Term> = r
86	        .conclusions
87	        .iter()
88	        .filter(|f| has_tag(f, t))
89	        .map(|f| &f.args[0])
90	        .collect();
91	
92	    // Fresh names generated by this rule (one per `Fr(v)` premise).
93	    let mut fresh_pool: Vec<&VarSpec> = r
94	        .premises
95	        .iter()
96	        .filter(|f| is_fresh_fact(f))
97	        .filter_map(|f| match &f.args[0] {
98	            Term::Var(v) => Some(v),
99	            _ => None,
100	        })
101	        .collect();
102	
103	    // net_new = conc_keys minus one matching prem_key each (carried instances).
104	    let mut prem_pool = prem_keys;
105	    for c in &conc_keys {
106	        if let Some(pos) = prem_pool.iter().position(|p| *p == *c) {
107	            prem_pool.remove(pos); // this conclusion instance was carried through
108	        } else {
109	            // Newly created: its first argument must be a distinct fresh name.
110	            match c {
111	                Term::Var(v) if v.sort == SortHint::Fresh => {
112	                    match fresh_pool.iter().position(|fv| **fv == *v) {
113	                        Some(pos) => {
114	                            fresh_pool.remove(pos);
115	                        }
116	                        None => return false, // fresh-sorted but not Fr-generated (or reused)
117	                    }
118	                }
119	                _ => return false, // first argument is not a freshly generated name
120	            }
121	        }
122	    }
123	    true
124	}
125	
126	/// The built-in `Fr` fact that generates a fresh name.
127	fn is_fresh_fact(f: &Fact) -> bool {
128	    !f.persistent && f.name == "Fr" && f.args.len() == 1
129	}
