1	//! Unit G — Message Derivation Checks (clean-room reimplementation).
2	//!
3	//! For each protocol rule, the prover decides whether every variable of the rule
4	//! is derivable by the intruder from the rule's premises. Variables that are not
5	//! derivable are reported under the wellformedness topic `Message Derivation
6	//! Checks`. The derivability decision is the prover's solver and is NOT
7	//! reimplemented here: it is supplied by the caller through [`DerivabilitySolver`].
8	//!
9	//! This crate owns three things, all characterized purely by black-box
10	//! observation of the reference tool (see workspace/BEHAVIOR.md and QUERIES.log):
11	//!   1. probe construction — which rules and which variables are handed to the
12	//!      solver (rule filtering, candidate-variable enumeration);
13	//!   2. the decision logic around solver outcomes (deactivation, timeouts,
14	//!      derivable/not-derivable);
15	//!   3. byte-exact report text and variable ordering.
16	
17	pub mod ast;
18	
19	use std::collections::{BTreeSet, HashSet};
20	
21	use ast::{Rule, RuleAttr, SortHint, Term, TheoryItem, Theory, VarSpec, Fact};
22	
23	/// A single wellformedness finding: a topic and its message body. Mirrors the
24	/// `WfError` surface of the wellformedness unit so findings compose into the
25	/// shared report model.
26	#[derive(Debug, Clone, PartialEq, Eq)]
27	pub struct WfError {
28	    pub topic: String,
29	    pub message: String,
30	}
31	
32	impl WfError {
33	    pub fn new(topic: impl Into<String>, message: impl Into<String>) -> Self {
34	        WfError { topic: topic.into(), message: message.into() }
35	    }
36	}
37	
38	/// A flat report, in the order findings are rendered.
39	pub type WfReport = Vec<WfError>;
40	
41	/// The exact topic string the reference tool prints for this check.
42	pub const DERIVATION_TOPIC: &str = "Message Derivation Checks";
43	
44	/// The exact introductory paragraph the reference tool prints once, before the
45	/// per-rule blocks. Two leading spaces; no trailing whitespace.
46	pub const DERIVATION_INTRO: &str =
47	    "  The variables of the following rule(s) are not derivable from their premises, you may be performing unintended pattern matching.";
48	
49	// --------------------------------------------------------------------------
50	// Caller-supplied decision callback
51	// --------------------------------------------------------------------------
52	
53	/// One derivability question: can the intruder derive `variable` (X) from
54	/// `premises` (Y) of `rule`, within `timeout_secs`? The full `rule` is provided
55	/// so a solver that needs more context than the premise facts can use it.
56	pub struct DerivProbe<'a> {
57	    pub rule_name: &'a str,
58	    pub rule: &'a Rule,
59	    pub variable: &'a VarSpec,
60	    pub premises: &'a [Fact],
61	    pub timeout_secs: u64,
62	}
63	
64	/// The solver's verdict for one probe.
65	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
66	pub enum Derivability {
67	    /// The intruder can derive the variable from the premises.
68	    Derivable,
69	    /// The intruder cannot derive the variable — it will be reported.
70	    NotDerivable,
71	    /// The derivation search exceeded the timeout budget without deciding.
72	    TimedOut,
73	}
74	
75	/// The decision callback this crate is parameterized over. In production it wraps
76	/// the prover's message-deduction solver; in tests it is stubbed.
77	pub trait DerivabilitySolver {
78	    fn check(&self, probe: &DerivProbe) -> Derivability;
79	}
80	
81	/// How a per-rule timeout is treated. See the residual note in BEHAVIOR.md §7:
82	/// a real per-rule timeout was not observable, so the policy is explicit here.
83	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
84	pub enum TimeoutPolicy {
85	    /// Suppress the whole rule's warning when any of its probes times out
86	    /// (fail-open; the chosen default, consistent with `timeout=0` suppressing
87	    /// all output).
88	    SuppressRule,
89	    /// Treat a timed-out probe like `Derivable` (skip only that variable) and
90	    /// still report the variables that were definitively not derivable.
91	    SkipVariable,
92	}
93	
94	impl Default for TimeoutPolicy {
95	    fn default() -> Self {
96	        TimeoutPolicy::SuppressRule
97	    }
98	}
