101	// Entry points
102	// --------------------------------------------------------------------------
103	
104	/// Run the message-derivation check over a theory with the default timeout
105	/// policy. `timeout_secs` mirrors `--derivcheck-timeout`: `0` deactivates the
106	/// check and returns an empty report without consulting the solver.
107	pub fn message_derivation_checks<S: DerivabilitySolver>(
108	    thy: &Theory,
109	    solver: &S,
110	    timeout_secs: u64,
111	) -> WfReport {
112	    message_derivation_checks_with(thy, solver, timeout_secs, TimeoutPolicy::default())
113	}
114	
115	/// As [`message_derivation_checks`], with an explicit timeout policy.
116	pub fn message_derivation_checks_with<S: DerivabilitySolver>(
117	    thy: &Theory,
118	    solver: &S,
119	    timeout_secs: u64,
120	    timeout_policy: TimeoutPolicy,
121	) -> WfReport {
122	    // `--derivcheck-timeout=0` deactivates the check entirely.
123	    if timeout_secs == 0 {
124	        return Vec::new();
125	    }
126	
127	    // Per-rule findings, kept in theory (source) order.
128	    let mut blocks: Vec<(String, Vec<VarSpec>)> = Vec::new();
129	
130	    for item in &thy.items {
131	        let rule = match item {
132	            TheoryItem::Rule(rule) => rule,
133	            _ => continue, // only protocol rules; intruder rules are out of scope
134	        };
135	        // A rule tagged [no_derivcheck] is skipped.
136	        if rule.attributes.iter().any(|a| matches!(a, RuleAttr::NoDerivCheck)) {
137	            continue;
138	        }
139	
140	        let candidates = candidate_variables(rule);
141	        let mut flagged: Vec<VarSpec> = Vec::new();
142	        let mut rule_timed_out = false;
143	
144	        for var in &candidates {
145	            let probe = DerivProbe {
146	                rule_name: &rule.name,
147	                rule,
148	                variable: var,
149	                premises: &rule.premises,
150	                timeout_secs,
151	            };
152	            match solver.check(&probe) {
153	                Derivability::Derivable => {}
154	                Derivability::NotDerivable => flagged.push(var.clone()),
155	                Derivability::TimedOut => match timeout_policy {
156	                    TimeoutPolicy::SuppressRule => {
157	                        rule_timed_out = true;
158	                        break;
159	                    }
160	                    TimeoutPolicy::SkipVariable => {}
161	                },
162	            }
163	        }
164	
165	        if rule_timed_out {
166	            continue;
167	        }
168	        if !flagged.is_empty() {
169	            sort_variables(&mut flagged);
170	            blocks.push((rule.name.clone(), flagged));
171	        }
172	    }
173	
174	    if blocks.is_empty() {
175	        return Vec::new();
176	    }
177	
178	    // The intro paragraph is emitted once, then one entry per failing rule; all
179	    // share the topic so the report groups them under a single header.
180	    let mut report: WfReport = Vec::with_capacity(blocks.len() + 1);
181	    report.push(WfError::new(DERIVATION_TOPIC, DERIVATION_INTRO));
182	    for (name, vars) in blocks {
183	        report.push(WfError::new(DERIVATION_TOPIC, rule_block(&name, &vars)));
184	    }
185	    report
186	}
