189	// Probe construction
190	// --------------------------------------------------------------------------
191	
192	/// The candidate variables handed to the solver for one rule: every distinct
193	/// variable occurring in the rule's premises, actions, conclusions, and let
194	/// bindings, in first-occurrence order (order is irrelevant — the flagged subset
195	/// is re-sorted for display). The solver decides which are actually derivable,
196	/// so this set is a safe superset: public names, `Fr`-bound fresh names, and
197	/// state-fact-bound variables are all resolved to `Derivable` by the solver.
198	pub fn candidate_variables(rule: &Rule) -> Vec<VarSpec> {
199	    let mut out: Vec<VarSpec> = Vec::new();
200	    let mut seen: HashSet<VarSpec> = HashSet::new();
201	    let push = |t: &Term, out: &mut Vec<VarSpec>, seen: &mut HashSet<VarSpec>| {
202	        collect_vars(t, &mut |v| {
203	            if seen.insert(v.clone()) {
204	                out.push(v.clone());
205	            }
206	        });
207	    };
208	    for f in &rule.premises {
209	        for a in &f.args {
210	            push(a, &mut out, &mut seen);
211	        }
212	    }
213	    for f in &rule.actions {
214	        for a in &f.args {
215	            push(a, &mut out, &mut seen);
216	        }
217	    }
218	    for f in &rule.conclusions {
219	        for a in &f.args {
220	            push(a, &mut out, &mut seen);
221	        }
222	    }
223	    for lb in &rule.let_block {
224	        push(&lb.var, &mut out, &mut seen);
225	        push(&lb.value, &mut out, &mut seen);
226	    }
227	    out
228	}
229	
230	/// Walk a term, invoking `f` on every variable occurrence.
231	fn collect_vars(term: &Term, f: &mut impl FnMut(&VarSpec)) {
232	    match term {
233	        Term::Var(v) => f(v),
234	        Term::PubLit(_)
235	        | Term::FreshLit(_)
236	        | Term::NatLit(_)
237	        | Term::Number(_)
238	        | Term::NumberOne
239	        | Term::NatOne
240	        | Term::DhNeutral => {}
241	        Term::App(_, args) | Term::Pair(args) => {
242	            for a in args {
243	                collect_vars(a, f);
244	            }
245	        }
246	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
247	            collect_vars(a, f);
248	            collect_vars(b, f);
249	        }
250	        Term::PatMatch(a) => collect_vars(a, f),
251	    }
252	}
