254	// --------------------------------------------------------------------------
255	// Variable ordering and rendering
256	// --------------------------------------------------------------------------
257	
258	/// Sort flagged variables into report order and drop duplicates. The order is
259	/// ascending by `(sort-rank, name lexicographically, index numerically)`.
260	pub fn sort_variables(vars: &mut Vec<VarSpec>) {
261	    vars.sort_by(var_order_key);
262	    vars.dedup();
263	}
264	
265	/// Total order used to sort reported variables (see BEHAVIOR.md §6).
266	fn var_order_key(a: &VarSpec, b: &VarSpec) -> std::cmp::Ordering {
267	    sort_rank(a.sort)
268	        .cmp(&sort_rank(b.sort))
269	        .then_with(|| a.name.cmp(&b.name)) // lexicographic string comparison
270	        .then_with(|| a.idx.cmp(&b.idx)) // numeric index comparison
271	}
272	
273	/// Sort-tag rank. Observed among reportable (non-derivable) variables:
274	/// `Fresh < Msg`. Message-sort variables carry either `Msg` or `Untagged` and
275	/// rank together. Other sorts (`Pub`, `Node`, `Nat`, `Suffix`) do not occur as
276	/// reported variables — public names are always derivable and node/nat are not
277	/// message terms — so their relative rank is unobserved and placed last.
278	fn sort_rank(sort: SortHint) -> u8 {
279	    match sort {
280	        SortHint::Fresh => 0,
281	        SortHint::Msg | SortHint::Untagged => 1,
282	        _ => 2,
283	    }
284	}
285	
286	/// Render one variable as the reference tool spells it in the warning: fresh
287	/// names carry a `~` prefix, public names a `$` prefix, message names none; a
288	/// nonzero index is appended as `.idx` (e.g. `x.2`).
289	pub fn render_variable(v: &VarSpec) -> String {
290	    let prefix = match v.sort {
291	        SortHint::Fresh => "~",
292	        SortHint::Pub => "$",
293	        _ => "",
294	    };
295	    if v.idx == 0 {
296	        format!("{}{}", prefix, v.name)
297	    } else {
298	        format!("{}{}.{}", prefix, v.name, v.idx)
299	    }
300	}
301	
302	/// The per-rule block body: `"Rule <name>: \nFailed to derive Variable(s): <v1>, <v2>, ..."`.
303	/// Note the trailing space after the colon on the first line.
304	fn rule_block(rule_name: &str, vars: &[VarSpec]) -> String {
305	    let list = vars
306	        .iter()
307	        .map(render_variable)
308	        .collect::<Vec<_>>()
309	        .join(", ");
310	    format!("Rule {}: \nFailed to derive Variable(s): {}", rule_name, list)
311	}
