314	// Rendering
315	// --------------------------------------------------------------------------
316	
317	/// A topic header exactly as the reference tool renders it: the title, then a
318	/// newline, then a run of `=` as long as the title, then a newline.
319	pub fn underline_topic(title: &str) -> String {
320	    let bar: String = "=".repeat(title.chars().count());
321	    format!("{}\n{}\n", title, bar)
322	}
323	
324	/// The distinct topics present in a report.
325	pub fn topics(report: &WfReport) -> BTreeSet<String> {
326	    report.iter().map(|e| e.topic.clone()).collect()
327	}
328	
329	/// Render the `Message Derivation Checks` topic block byte-exactly. Returns the
330	/// empty string for an empty report. The block has no trailing newline; the
331	/// surrounding report writer adds separators between topic blocks.
332	pub fn render_derivation_report(report: &WfReport) -> String {
333	    let messages: Vec<&str> = report
334	        .iter()
335	        .filter(|e| e.topic == DERIVATION_TOPIC)
336	        .map(|e| e.message.as_str())
337	        .collect();
338	    if messages.is_empty() {
339	        return String::new();
340	    }
341	    format!(
342	        "{}\n{}",
343	        underline_topic(DERIVATION_TOPIC),
344	        messages.join("\n\n")
345	    )
346	}
