638	        impl DerivabilitySolver for Mixed {
639	            fn check(&self, p: &DerivProbe) -> Derivability {
640	                match p.variable.name.as_str() {
641	                    "xx" => Derivability::NotDerivable,
642	                    "yy" => Derivability::TimedOut,
643	                    _ => Derivability::Derivable,
644	                }
645	            }
646	        }
647	        let r = rule(
648	            "R",
649	            vec![fact("In", vec![app("h", vec![v("xx"), v("yy")])])],
650	            vec![],
651	            vec![],
652	        );
653	        let thy = theory(vec![TheoryItem::Rule(r)]);
654	        let report =
655	            message_derivation_checks_with(&thy, &Mixed, 5, TimeoutPolicy::SkipVariable);
656	        assert!(render_derivation_report(&report).ends_with("Variable(s): xx"));
657	    }
